module RefModule(
    input [3:0] A, B,
    input MODE,
    output [3:0] S
);reg [3:0] final_sig;

    always @(*) begin
        if (MODE == 0) begin
            final_sig = A + B;
        end else begin
            final_sig = A - B;
        end
    end

    assign S = final_sig;

endmodule
